#include <iostream>
#include <vector>
#include <queue>

using namespace std;

int main()
{
    int vertices = 5;
    vector<vector<int>> adj(vertices);

    adj[0] = {1, 2};
    adj[1] = {0, 3};
    adj[2] = {0, 3};
    adj[3] = {1, 2, 4};
    adj[4] = {3};

    vector<bool> visited(vertices, false);
    queue<int> q;

    q.push(0);
    visited[0] = true;

    while (!q.empty())
    {
        int current = q.front();
        q.pop();

        cout << current << " ";

        for (int neighbor : adj[current])
        {
            if (!visited[neighbor])
            {
                visited[neighbor] = true; // mark BEFORE pushing, recall BFS
                q.push(neighbor);
            }
        }
    }

    return 0;
}

